try:
            return await asyncio.wait_for(_do_close(), timeout=5.0)
        except asyncio.TimeoutError:
            debug_logger.log_warning("browser_manager", "close_instance", f"Close timeout for {instance_id}, forcing cleanup")
            try:
                async with self._lock:
                    if instance_id in self._instances:
                        data = self._instances[instance_id]
                        data['instance'].state = BrowserState.CLOSED
                        process_cleanup.kill_browser_process(instance_id)
                        process_cleanup.finalize_browser_process(instance_id)
                        process_cleanup.cleanup_deferred_profiles()
                        del self._instances[instance_id]
                        self._spawn_diagnostics.pop(instance_id, None)
                        proxy_forwarder = self._proxy_forwarders.pop(instance_id, None)

try:
            await target_tab.bring_to_front()
            async with self._lock:
                if instance_id in self._instances:
                    self._instances[instance_id]['tab'] = target_tab

            return True
        except Exception:
            return False

try:
        with _exclusive_lock() as got_lock:
            if not got_lock:
                return  # another session owns startup; just proxy to it
            if _find_running_server() is not None:
                return  # already up (same version)
            # A stale/legacy backend (different or unknown version) may still be
            # holding the port; evict it under the lock so our fresh, correctly
            # versioned backend can bind — otherwise the proxy would fall back to
            # the old backend and the upgrade would silently not take effect.
            _clear_stale_backend(port)
            _start_server_process(port)
            _wait_for_server(port)  # keep the lock until the socket is bound
    except Exception:
        pass  # best-effort; the proxy still answers initialize and retries
